<!DOCTYPE html>
<html>
<head>
  <title>Maze Game</title>
  <style>
    body {
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    #maze {
      border: 1px solid black;
      width: 400px;
      height: 400px;
      margin: 20px;
    }

    .cell {
      width: 10px;
      height: 10px;
      position: absolute;
    }

    .wall-n {
      border-top: 1px solid black;
    }

    .wall-e {
      border-right: 1px solid black;
    }

    .wall-s {
      border-bottom: 1px solid black;
    }

    .wall-w {
      border-left: 1px solid black;
    }

    .bot {
      width: 8px;
      height: 8px;
      position: absolute;
      border-radius: 50%;
    }
  </style>
</head>
<body>
  <h1>Maze Game</h1>
  <div id="maze"></div>
  <div>
    <p>Completed: <span id="completed">0</span></p>
    <p>Timer: <span id="timer">0</span></p>
    <button id="reset">Reset</button>
  </div>

  <script>
    const mazeElement = document.getElementById('maze');
    const completedSpan = document.getElementById('completed');
    const timerSpan = document.getElementById('timer');
    const resetButton = document.getElementById('reset');

    let rows = 25;
    let cols = 25;
    let gameSize = { rows: rows, cols: cols };
    let bots = [];
    let mazeData = null;
    let elapsed = 0;
    let lastBotFinishTick = null;

    const seed = 42; // Fixed seed for reproducibility

    function createMaze() {
      // Simple maze generation (can be improved)
      mazeData = Array(rows).fill(null).map(() => Array(cols).fill(0));
      for (let r = 1; r < rows - 1; r++) {
        for (let c = 1; c < cols - 1; c++) {
          if ((r % 2 === 1 && c % 2 === 1) || (r % 2 === 0 && c % 2 === 0)) {
            mazeData[r][c] = 1; // Wall
          }
        }
      }

      // Ensure entrance and exit
      mazeData[0][1] = 0; // Entrance
      mazeData[rows - 1][cols - 2] = 0; // Exit
    }

    function spawnBots() {
      for (let i = 0; i < 24; i++) {
        const bot = {
          path: [],
          deadEnds: [],
          finishTick: null,
          r: 0,
          c: 1, // Start at the entrance
        };
        bots.push(bot);
      }
    }

    function drawMaze() {
      const cellWidth = mazeElement.offsetWidth / cols;
      const cellHeight = mazeElement.offsetHeight / rows;

      for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
          const cell = document.createElement('div');
          cell.classList.add('cell');
          cell.style.width = `${cellWidth}px`;
          cell.style.height = `${cellHeight}px`;
          cell.style.left = `${c * cellWidth}px`;
          cell.style.top = `${r * cellHeight}px`;

          if (mazeData[r][c] === 1) {
            // Add walls
            if (mazeData[r][c + 1] === 1) cell.classList.add('wall-e');
            if (mazeData[r][c - 1] === 1) cell.classList.add('wall-w');
            if (mazeData[r + 1][c] === 1) cell.classList.add('wall-s');
            if (mazeData[r - 1][c] === 1) cell.classList.add('wall-n');
          }

          mazeElement.appendChild(cell);
        }
      }
    }

    function drawBots() {
      bots.forEach((bot, index) => {
        const botDiv = document.createElement('div');
        botDiv.classList.add('bot');
        botDiv.style.left = `${bot.c * 10}px`;
        botDiv.style.top = `${bot.r * 10}px`;
        botDiv.style.backgroundColor = `hsl(${index * 360 / 24}, 100%, 50%)`; // Different colors

        mazeElement.appendChild(botDiv);
      });
    }


    function tick(n) {
      elapsed++;
      timerSpan.textContent = elapsed;

      if (bots.some(bot => bot.finishTick !== null)) {
        lastBotFinishTick = bots.find(bot => bot.finishTick !== null).finishTick;
        completedSpan.textContent = bots.filter(bot => bot.finishTick !== null).length;
        return; // Freeze if any bot has finished
      }

      bots.forEach((bot, index) => {
        if (bot.finishTick !== null) return;

        const r = bot.r;
        const c = bot.c;

        // Check for walls
        const eWall = mazeData[r][c + 1] === 1;
        const wWall = mazeData[r][c - 1] === 1;
        const sWall = mazeData[r + 1][c] === 1;
        const nWall = mazeData[r - 1][c] === 1;

        // Check for dead ends
        let isDeadEnd = false;
        if (eWall && bot.path.length > 0) isDeadEnd = true;
        if (wWall && bot.path.length > 0) isDeadEnd = true;
        if (sWall && bot.path.length > 0) isDeadEnd = true;
        if (nWall && bot.path.length > 0) isDeadEnd = true;

        // Movement logic - Tremaux/DFS with dead end avoidance
        let dr, dc;
        if (eWall) dr = 0; if (wWall) dc = -1; if (sWall) dr = 1; if (nWall) dc = 1;
        else if (eWall) dr = 0; if (wWall) dc = -1; if (sWall) dr = 1; if (nWall) dc = 1;
        else {
          dr = Math.floor(Math.random() * 2) - 1; // Random direction
          dc = Math.floor(Math.random() * 2) - 1;
        }

        const nr = r + dr;
        const nc = c + dc;

        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && mazeData[nr][nc] === 0 && !bot.deadEnds.some(d => d.r === nr && d.c === nc)) {
          bot.path.push({ r: nr, c: nc });
          bot.r = nr;
          bot.c = nc;
        } else if (isDeadEnd) {
          bot.deadEnds.push({ r: r, c: c });
        }
      });
    }

    function reset(newSeed) {
      seed = newSeed || seed;
      createMaze();
      spawnBots();
      elapsed = 0;
      lastBotFinishTick = null;
      completedSpan.textContent = 0;
      timerSpan.textContent = 0;
      bots.forEach(bot => {
        bot.path = [];
        bot.deadEnds = [];
        bot.finishTick = null;
      });
      drawMaze();
      drawBots();
    }

    resetButton.addEventListener('click', () => reset());

    // Initial setup
    createMaze();
    spawnBots();
    drawMaze();
    drawBots();

    // Game loop
    setInterval(() => tick(1), 10); // Adjust interval for speed
  </script>
</body>
</html>
